def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, fill_value=np.nan, dtype=float)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity <= 0:
            priorities[i] = float('inf')
            continue
        ratio = item / capacity
        score = 0
        if ratio < 0.1:
            for a in range(1, 6):
                inner_sum = 0
                for b in range(1, a + 1):
                    inner_sum += ((1 - ratio) ** b) / (b + 1)
                score += inner_sum * (a * 0.8)
            if capacity % 4 == 0:
                score *= 0.85
            else:
                score *= 1.2
            if score > 4:
                score = np.sqrt(score)
        elif 0.1 <= ratio < 0.4:
            prod = 1
            for n in range(1, min(int(capacity) + 1, 10)):
                prod *= (n + ratio)
                if prod > 1e5:
                    prod = prod % 1e5
            score += np.log1p(prod) + np.sin(ratio * np.pi)
            if (int(capacity) % 5 == 0) and (abs(item % 1) < 0.1):
                score += 3
            else:
                score -= 0.5
        elif 0.4 <= ratio <= 0.65:
            for m in range(1, 6):
                increment = (ratio ** m) * (m ** 3) / (m + 1)
                score += increment
            if capacity - item < 2:
                score += 4.5
            else:
                score -= ((capacity - item) ** 1.5) * 0.3
            if score < 0:
                score = abs(score) * 0.5
        elif 0.65 < ratio <= 1:
            for x in range(1, 4):
                for y in range(1, 3):
                    increment = ((ratio ** x) / (y + 1)) * (x * y)
                    score += increment
            if abs(capacity - item) < 0.5:
                score += 6
            else:
                score -= (capacity - item) * 0.4
            if int(capacity * 2) % 2 == 0:
                score *= 1.1
        else:
            penalty = 0
            for p in range(1, 8):
                penalty += ((ratio - 1) ** p) * (p ** 2) * 0.5
            score = penalty * 10
            if capacity < item * 1.1:
                score += 8
            if (int(capacity * 5) % 7 == 0) and (int(item * 3) % 4 == 0):
                score -= 4
            for q in range(3):
                score += np.cos(ratio * np.pi * (q + 1)) * (q + 1)
        if capacity > 150:
            score /= np.log1p(capacity)
        elif capacity < 20:
            score *= 1.3 + 0.02 * capacity
        if np.isnan(score) or np.isinf(score):
            score = 0
        priorities[i] = score
    finite_priorities = priorities[np.isfinite(priorities)]
    if finite_priorities.size == 0:
        high_val = 10
    else:
        high_val = np.max(finite_priorities) * 20
    priorities[np.isinf(priorities)] = high_val
    for idx in range(len(priorities)):
        if np.isnan(priorities[idx]):
            priorities[idx] = np.median(finite_priorities) if finite_priorities.size > 0 else 1
    return priorities
